        vector<bool> answer(queries.size());
        for (int i = 0; i < queries.size(); i++) {
            int a = queries[i][0];
            int b = queries[i][1];
            int c = queries[i][2];
            int d = queries[i][3];

            int n = s.length();

            int k = (n / 2);

            string sub1 = s.substr(a, k);
            string sub2 = s.substr(b, n - k);

